#!/usr/bin/env bash
set -euo pipefail
DIR="/home/tanarit/monitor-rutnin.com"
cd "$DIR"

echo "==> Writing ftp_listing_diff.py"
base64 -d > ftp_listing_diff.py <<'B64_EOF'

B64_EOF

echo "==> Writing apply_server_patch.py"
base64 -d > apply_server_patch.py <<'B64_EOF'

B64_EOF

cp monitor.py monitor.py.bak.$(date +%Y%m%d_%H%M%S) 2>/dev/null || true
./venv/bin/python apply_server_patch.py
./venv/bin/python -m py_compile monitor.py ftp_listing_diff.py
./venv/bin/python monitor.py
echo "==> Deploy OK"
